-- supabase/migrations/20260602021157_transactional_payment_rpc.sql
-- ============================================================
create or replace function app_record_receivable_payment(
  p_receivable_id uuid,
  p_amount numeric,
  p_currency text default null,
  p_payment_date date default null,
  p_payment_method text default null,
  p_reference_no text default null,
  p_fx_rate numeric default null,
  p_base_currency_amount numeric default null,
  p_allow_overpayment boolean default false
)
returns jsonb
language plpgsql
security invoker
set search_path = public
as $$
declare
  v_receivable receivables%rowtype;
  v_payment payments%rowtype;
  v_amount numeric(18,2);
  v_current_received numeric(18,2);
  v_current_balance numeric(18,2);
  v_next_received numeric(18,2);
  v_next_balance numeric(18,2);
begin
  if not app_is_any_role(array['admin', 'manager', 'finance']) then
    raise exception 'insufficient_finance_role' using errcode = '42501';
  end if;

  v_amount := round(coalesce(p_amount, 0)::numeric, 2);

  if v_amount <= 0 then
    raise exception 'payment_amount_must_be_positive';
  end if;

  select * into v_receivable
  from receivables
  where id = p_receivable_id
  for update;

  if not found then
    raise exception 'receivable_not_found';
  end if;

  if p_currency is not null and p_currency <> v_receivable.currency then
    raise exception 'payment_currency_mismatch';
  end if;

  v_current_received := round(coalesce(v_receivable.amount_received, 0)::numeric, 2);
  v_current_balance := round(coalesce(v_receivable.balance_amount, v_receivable.amount_due - v_current_received, 0)::numeric, 2);

  if v_receivable.status = 'closed' or v_current_balance <= 0 then
    raise exception 'receivable_already_closed';
  end if;

  if not p_allow_overpayment and v_amount > v_current_balance then
    raise exception 'payment_exceeds_receivable_balance';
  end if;

  if nullif(trim(coalesce(p_reference_no, '')), '') is not null and exists (
    select 1
    from payments
    where receivable_id = p_receivable_id
      and reference_no = trim(p_reference_no)
      and status <> 'void'
  ) then
    raise exception 'duplicate_payment_reference';
  end if;

  v_next_received := v_current_received + v_amount;
  v_next_balance := greatest(round((v_receivable.amount_due - v_next_received)::numeric, 2), 0);

  insert into payments (
    payment_no,
    payment_type,
    party_type,
    party_id,
    receivable_id,
    currency,
    amount,
    fx_rate,
    base_currency_amount,
    payment_method,
    payment_date,
    reference_no,
    status
  )
  values (
    app_next_doc_no('RCPT'),
    'receipt',
    'customer',
    v_receivable.customer_id,
    v_receivable.id,
    v_receivable.currency,
    v_amount,
    p_fx_rate,
    p_base_currency_amount,
    p_payment_method,
    coalesce(p_payment_date, current_date),
    nullif(trim(coalesce(p_reference_no, '')), ''),
    'confirmed'
  )
  returning * into v_payment;

  update receivables
  set
    amount_received = v_next_received,
    balance_amount = v_next_balance,
    status = case when v_next_balance = 0 then 'closed' else 'partial' end
  where id = v_receivable.id
  returning * into v_receivable;

  return jsonb_build_object(
    'payment', to_jsonb(v_payment),
    'receivable', to_jsonb(v_receivable),
    'amount_applied', v_amount,
    'balance_amount', v_receivable.balance_amount
  );
end;
$$;

create or replace function app_record_payable_payment(
  p_payable_id uuid,
  p_amount numeric,
  p_currency text default null,
  p_payment_date date default null,
  p_payment_method text default null,
  p_reference_no text default null,
  p_fx_rate numeric default null,
  p_base_currency_amount numeric default null,
  p_allow_overpayment boolean default false
)
returns jsonb
language plpgsql
security invoker
set search_path = public
as $$
declare
  v_payable payables%rowtype;
  v_payment payments%rowtype;
  v_amount numeric(18,2);
  v_current_paid numeric(18,2);
  v_current_balance numeric(18,2);
  v_next_paid numeric(18,2);
  v_next_balance numeric(18,2);
begin
  if not app_is_any_role(array['admin', 'manager', 'finance']) then
    raise exception 'insufficient_finance_role' using errcode = '42501';
  end if;

  v_amount := round(coalesce(p_amount, 0)::numeric, 2);

  if v_amount <= 0 then
    raise exception 'payment_amount_must_be_positive';
  end if;

  select * into v_payable
  from payables
  where id = p_payable_id
  for update;

  if not found then
    raise exception 'payable_not_found';
  end if;

  if p_currency is not null and p_currency <> v_payable.currency then
    raise exception 'payment_currency_mismatch';
  end if;

  v_current_paid := round(coalesce(v_payable.amount_paid, 0)::numeric, 2);
  v_current_balance := round(coalesce(v_payable.balance_amount, v_payable.amount_due - v_current_paid, 0)::numeric, 2);

  if v_payable.status = 'closed' or v_current_balance <= 0 then
    raise exception 'payable_already_closed';
  end if;

  if not p_allow_overpayment and v_amount > v_current_balance then
    raise exception 'payment_exceeds_payable_balance';
  end if;

  if nullif(trim(coalesce(p_reference_no, '')), '') is not null and exists (
    select 1
    from payments
    where payable_id = p_payable_id
      and reference_no = trim(p_reference_no)
      and status <> 'void'
  ) then
    raise exception 'duplicate_payment_reference';
  end if;

  v_next_paid := v_current_paid + v_amount;
  v_next_balance := greatest(round((v_payable.amount_due - v_next_paid)::numeric, 2), 0);

  insert into payments (
    payment_no,
    payment_type,
    party_type,
    party_id,
    payable_id,
    currency,
    amount,
    fx_rate,
    base_currency_amount,
    payment_method,
    payment_date,
    reference_no,
    status
  )
  values (
    app_next_doc_no('PAY'),
    'payment',
    'vendor',
    v_payable.vendor_id,
    v_payable.id,
    v_payable.currency,
    v_amount,
    p_fx_rate,
    p_base_currency_amount,
    p_payment_method,
    coalesce(p_payment_date, current_date),
    nullif(trim(coalesce(p_reference_no, '')), ''),
    'confirmed'
  )
  returning * into v_payment;

  update payables
  set
    amount_paid = v_next_paid,
    balance_amount = v_next_balance,
    status = case when v_next_balance = 0 then 'closed' else 'partial' end
  where id = v_payable.id
  returning * into v_payable;

  return jsonb_build_object(
    'payment', to_jsonb(v_payment),
    'payable', to_jsonb(v_payable),
    'amount_applied', v_amount,
    'balance_amount', v_payable.balance_amount
  );
end;
$$;

revoke execute on function app_record_receivable_payment(uuid, numeric, text, date, text, text, numeric, numeric, boolean) from public, anon;
revoke execute on function app_record_payable_payment(uuid, numeric, text, date, text, text, numeric, numeric, boolean) from public, anon;

grant execute on function app_record_receivable_payment(uuid, numeric, text, date, text, text, numeric, numeric, boolean) to authenticated, service_role;
grant execute on function app_record_payable_payment(uuid, numeric, text, date, text, text, numeric, numeric, boolean) to authenticated, service_role;

-- ============================================================
-- supabase/migrations/20260602041708_pricing_recalculation_rpc.sql
-- ============================================================
create or replace function app_recalculate_quote_pricing(
  p_transport_mode text,
  p_shipment_type text,
  p_origin text default null,
  p_destination text default null,
  p_volume_cbm numeric default 0,
  p_weight_kg numeric default 0,
  p_container_qty numeric default 1,
  p_container_type text default null,
  p_customer_id uuid default null,
  p_quote_date date default null,
  p_min_margin numeric default 0.18
)
returns jsonb
language plpgsql
security invoker
set search_path = public
as $$
declare
  v_rate_sheet rate_sheets%rowtype;
  v_customer customers%rowtype;
  v_item rate_sheet_items%rowtype;
  v_items jsonb := '[]'::jsonb;
  v_warnings jsonb := '[]'::jsonb;
  v_quote_date date := coalesce(p_quote_date, current_date);
  v_origin text := lower(coalesce(p_origin, ''));
  v_destination text := lower(coalesce(p_destination, ''));
  v_route_score integer := 0;
  v_target_margin numeric := greatest(coalesce(p_min_margin, 0.18), 0.01);
  v_qty numeric(18,3);
  v_cost numeric(18,2);
  v_revenue numeric(18,2);
  v_profit numeric(18,2);
  v_revenue_total numeric(18,2) := 0;
  v_cost_total numeric(18,2) := 0;
  v_profit_total numeric(18,2) := 0;
  v_margin numeric(8,4) := 0;
  v_currency text := 'USD';
  v_currency_mismatch boolean := false;
begin
  if not app_is_any_role(array['admin', 'manager', 'sales', 'ops', 'finance']) then
    raise exception 'insufficient_pricing_role' using errcode = '42501';
  end if;

  if p_transport_mode is null or p_shipment_type is null then
    raise exception 'pricing_mode_and_shipment_type_required';
  end if;

  if p_customer_id is not null then
    select * into v_customer
    from customers
    where id = p_customer_id;

    if v_customer.status in ('active', 'vip', 'key_account') or v_customer.customer_type in ('vip', 'key_account') then
      v_target_margin := greatest(v_target_margin, 0.18);
    elsif v_customer.status in ('prospect', 'new') then
      v_target_margin := greatest(v_target_margin, 0.22);
    else
      v_target_margin := greatest(v_target_margin, 0.20);
    end if;
  end if;

  select *
  into v_rate_sheet
  from (
    select
      rs.*,
      (
        case
          when rs.origin_port is not null and v_origin like '%' || lower(rs.origin_port) || '%' then 35
          when rs.origin_country is not null and v_origin like '%' || lower(rs.origin_country) || '%' then 20
          when rs.origin_port is null and rs.origin_country is null then 5
          else 0
        end
        +
        case
          when rs.destination_port is not null and v_destination like '%' || lower(rs.destination_port) || '%' then 35
          when rs.destination_country is not null and v_destination like '%' || lower(rs.destination_country) || '%' then 20
          when rs.destination_port is null and rs.destination_country is null then 5
          else 0
        end
        +
        case
          when rs.effective_from is not null and rs.effective_to is not null then 10
          else 0
        end
      ) as match_score
    from rate_sheets rs
    where rs.mode = p_transport_mode::transport_mode
      and rs.shipment_type = p_shipment_type::shipment_type
      and rs.status = 'active'
      and (rs.effective_from is null or rs.effective_from <= v_quote_date)
      and (rs.effective_to is null or rs.effective_to >= v_quote_date)
  ) ranked
  order by ranked.match_score desc, ranked.priority asc, ranked.effective_from desc nulls last, ranked.created_at desc
  limit 1;

  if v_rate_sheet.id is null then
    raise exception 'no_active_rate_sheet_matched';
  end if;

  v_currency := coalesce(v_rate_sheet.currency, 'USD');

  v_route_score :=
    case
      when v_rate_sheet.origin_port is not null and v_origin like '%' || lower(v_rate_sheet.origin_port) || '%' then 35
      when v_rate_sheet.origin_country is not null and v_origin like '%' || lower(v_rate_sheet.origin_country) || '%' then 20
      when v_rate_sheet.origin_port is null and v_rate_sheet.origin_country is null then 5
      else 0
    end
    +
    case
      when v_rate_sheet.destination_port is not null and v_destination like '%' || lower(v_rate_sheet.destination_port) || '%' then 35
      when v_rate_sheet.destination_country is not null and v_destination like '%' || lower(v_rate_sheet.destination_country) || '%' then 20
      when v_rate_sheet.destination_port is null and v_rate_sheet.destination_country is null then 5
      else 0
    end;

  if v_route_score < 40 then
    v_warnings := v_warnings || jsonb_build_array('路线匹配较弱，请人工确认起运地、目的地和费率表适用范围。');
  end if;

  if v_rate_sheet.effective_from is null or v_rate_sheet.effective_to is null then
    v_warnings := v_warnings || jsonb_build_array('费率表缺少完整有效期，发报价前建议复核。');
  end if;

  for v_item in
    select *
    from rate_sheet_items
    where rate_sheet_id = v_rate_sheet.id
      and included_in_quote = true
    order by sort_order asc, created_at asc
  loop
    v_qty := case v_item.calc_method::text
      when 'per_cbm' then greatest(coalesce(p_volume_cbm, 0), coalesce(v_item.min_qty, 0), 1)
      when 'per_kg' then greatest(coalesce(p_weight_kg, 0), coalesce(v_item.min_qty, 0), 1)
      when 'per_container' then greatest(coalesce(p_container_qty, 1), coalesce(v_item.min_qty, 0), 1)
      else 1
    end;

    if v_item.calc_method::text = 'tiered' then
      v_warnings := v_warnings || jsonb_build_array('存在阶梯价费项，当前按基础单价核算，需人工复核。');
    end if;

    if v_item.container_type is not null
      and p_container_type is not null
      and v_item.container_type <> p_container_type then
      continue;
    end if;

    v_cost := greatest(round((v_qty * coalesce(v_item.unit_price, 0))::numeric, 2), coalesce(v_item.min_charge, 0));
    v_revenue := round((v_cost / greatest(1 - v_target_margin, 0.01))::numeric, 2);
    v_profit := v_revenue - v_cost;

    if coalesce(v_item.currency, v_currency) <> v_currency then
      v_currency_mismatch := true;
    end if;

    v_cost_total := v_cost_total + v_cost;
    v_revenue_total := v_revenue_total + v_revenue;
    v_profit_total := v_profit_total + v_profit;

    v_items := v_items || jsonb_build_array(jsonb_build_object(
      'rate_sheet_item_id', v_item.id,
      'fee_code', v_item.fee_code,
      'fee_name', v_item.fee_name,
      'qty', v_qty,
      'unit', v_item.unit,
      'unit_price', v_item.unit_price,
      'currency', coalesce(v_item.currency, v_currency),
      'revenue_amount', v_revenue,
      'estimated_cost_amount', v_cost,
      'profit_amount', v_profit,
      'profit_margin', case when v_revenue > 0 then round((v_profit / v_revenue)::numeric, 4) else 0 end
    ));
  end loop;

  if jsonb_array_length(v_items) = 0 then
    raise exception 'rate_sheet_has_no_quote_items';
  end if;

  if v_currency_mismatch then
    v_warnings := v_warnings || jsonb_build_array('费率行存在多币种，当前未做汇率换算，请财务复核。');
  end if;

  v_margin := case when v_revenue_total > 0 then round((v_profit_total / v_revenue_total)::numeric, 4) else 0 end;

  if v_margin < coalesce(p_min_margin, 0.18) then
    v_warnings := v_warnings || jsonb_build_array('毛利率低于最低要求，必须提交审批后再发送。');
  end if;

  if jsonb_array_length(v_warnings) = 0 then
    v_warnings := jsonb_build_array('已按路线、有效期、优先级和目标毛利完成自动核价。');
  end if;

  return jsonb_build_object(
    'matched_rate_sheet_id', v_rate_sheet.id,
    'matched_rate_sheet_name', v_rate_sheet.name,
    'currency', v_currency,
    'route_match_score', v_route_score,
    'target_margin', v_target_margin,
    'pricing_status', case when v_margin < coalesce(p_min_margin, 0.18) or v_route_score < 40 then 'needs_review' else 'auto_calculated' end,
    'items', v_items,
    'summary', jsonb_build_object(
      'estimated_revenue_total', v_revenue_total,
      'estimated_cost_total', v_cost_total,
      'estimated_profit_total', v_profit_total,
      'estimated_profit_margin', v_margin
    ),
    'warnings', v_warnings
  );
end;
$$;

revoke execute on function app_recalculate_quote_pricing(text, text, text, text, numeric, numeric, numeric, text, uuid, date, numeric) from public, anon;
grant execute on function app_recalculate_quote_pricing(text, text, text, text, numeric, numeric, numeric, text, uuid, date, numeric) to authenticated, service_role;

-- ============================================================
-- supabase/migrations/20260602062921_order_status_update_rpc.sql
-- ============================================================
create or replace function app_update_order_status(
  p_order_id uuid,
  p_status text,
  p_action text default null,
  p_actor_name text default null
)
returns jsonb
language plpgsql
security invoker
set search_path = public
as $$
declare
  v_order orders%rowtype;
  v_previous_status order_status;
  v_next_status order_status;
  v_log order_operation_logs%rowtype;
begin
  if p_order_id is null or p_status is null then
    raise exception 'order_id_and_status_required';
  end if;

  v_next_status := p_status::order_status;

  select * into v_order
  from orders
  where id = p_order_id
  for update;

  if not found then
    raise exception 'order_not_found';
  end if;

  if not (
    app_is_any_role(array['admin', 'manager', 'ops'])
    or v_order.sales_owner_id = auth.uid()
  ) then
    raise exception 'insufficient_order_status_role' using errcode = '42501';
  end if;

  if v_order.status = 'closed' and v_next_status <> 'closed' and not app_is_any_role(array['admin', 'manager']) then
    raise exception 'closed_order_requires_manager';
  end if;

  v_previous_status := v_order.status;

  update orders
  set
    status = v_next_status,
    updated_at = now()
  where id = p_order_id
  returning * into v_order;

  insert into order_operation_logs (
    order_id,
    actor_id,
    actor_name,
    log_type,
    action,
    before_value,
    after_value
  )
  values (
    v_order.id,
    auth.uid(),
    coalesce(nullif(trim(coalesce(p_actor_name, '')), ''), 'system'),
    'status_update',
    coalesce(p_action, '订单状态更新'),
    jsonb_build_object('status', v_previous_status),
    jsonb_build_object('status', v_order.status)
  )
  returning * into v_log;

  return jsonb_build_object(
    'order', to_jsonb(v_order),
    'operation_log', to_jsonb(v_log),
    'previous_status', v_previous_status,
    'status', v_order.status
  );
end;
$$;

revoke execute on function app_update_order_status(uuid, text, text, text) from public, anon;
grant execute on function app_update_order_status(uuid, text, text, text) to authenticated, service_role;

-- ============================================================
-- supabase/migrations/20260602063911_order_task_rpc_and_list_view.sql
-- ============================================================
drop view if exists order_list_view;

create view order_list_view
with (security_invoker = true)
as
select
  orders.id,
  orders.order_no,
  orders.quote_id,
  orders.customer_id,
  orders.contact_id,
  customers.company_name as customer_name,
  customers.customer_no,
  quotes.quote_no,
  orders.transport_mode,
  orders.shipment_type,
  orders.booking_no,
  orders.origin,
  orders.destination,
  orders.cargo_desc,
  orders.container_type,
  orders.volume_cbm,
  orders.weight_kg,
  orders.quoted_revenue_total,
  orders.quoted_cost_total,
  orders.quoted_profit_total,
  orders.actual_revenue_total,
  orders.actual_cost_total,
  orders.actual_profit_total,
  orders.status,
  orders.settlement_status,
  orders.sales_owner_id,
  orders.ops_owner_id,
  orders.created_at,
  orders.updated_at,
  coalesce(receivable_rollup.amount_due, 0) as receivable_amount_due,
  coalesce(receivable_rollup.amount_received, 0) as receivable_amount_received,
  coalesce(receivable_rollup.balance_amount, 0) as receivable_balance_amount,
  coalesce(payable_rollup.amount_due, 0) as payable_amount_due,
  coalesce(payable_rollup.amount_paid, 0) as payable_amount_paid,
  coalesce(payable_rollup.balance_amount, 0) as payable_balance_amount,
  case
    when coalesce(receivable_rollup.balance_amount, 0) = 0 and coalesce(receivable_rollup.amount_due, 0) > 0 then '已结清'
    when coalesce(receivable_rollup.amount_received, 0) > 0 then '部分收款'
    when coalesce(receivable_rollup.amount_due, 0) > 0 then '未结清'
    else '待生成'
  end as receivable_status,
  case
    when exists (
      select 1
      from order_task_items
      where order_task_items.order_id = orders.id
        and order_task_items.group_name = '报关'
        and order_task_items.status <> 'done'
    ) then '未完成'
    when exists (
      select 1
      from order_task_items
      where order_task_items.order_id = orders.id
        and order_task_items.group_name = '报关'
    ) then '已完成'
    else '待确认'
  end as customs_status
from orders
left join customers on customers.id = orders.customer_id
left join quotes on quotes.id = orders.quote_id
left join lateral (
  select
    sum(amount_due) as amount_due,
    sum(amount_received) as amount_received,
    sum(balance_amount) as balance_amount
  from receivables
  where receivables.order_id = orders.id
) receivable_rollup on true
left join lateral (
  select
    sum(amount_due) as amount_due,
    sum(amount_paid) as amount_paid,
    sum(balance_amount) as balance_amount
  from payables
  where payables.order_id = orders.id
) payable_rollup on true;

grant select on order_list_view to authenticated, service_role;

create or replace function app_update_order_task_status(
  p_task_id uuid,
  p_status text,
  p_actor_name text default null
)
returns jsonb
language plpgsql
security invoker
set search_path = public
as $$
declare
  v_task order_task_items%rowtype;
  v_order orders%rowtype;
  v_previous_status text;
  v_log order_operation_logs%rowtype;
begin
  if p_task_id is null or p_status is null then
    raise exception 'task_id_and_status_required';
  end if;

  if p_status not in ('not_started', 'pending', 'in_progress', 'done', 'blocked', 'skipped') then
    raise exception 'invalid_task_status';
  end if;

  select * into v_task
  from order_task_items
  where id = p_task_id
  for update;

  if not found then
    raise exception 'order_task_not_found';
  end if;

  select * into v_order
  from orders
  where id = v_task.order_id
  for update;

  if not found then
    raise exception 'order_not_found';
  end if;

  if not (
    app_is_any_role(array['admin', 'manager', 'ops'])
    or v_order.sales_owner_id = auth.uid()
  ) then
    raise exception 'insufficient_order_task_role' using errcode = '42501';
  end if;

  v_previous_status := v_task.status;

  update order_task_items
  set
    status = p_status,
    completed_count = case when p_status = 'done' then total_count else 0 end,
    completed_at = case when p_status = 'done' then now() else null end,
    updated_at = now()
  where id = v_task.id
  returning * into v_task;

  insert into order_operation_logs (
    order_id,
    actor_id,
    actor_name,
    log_type,
    action,
    before_value,
    after_value
  )
  values (
    v_order.id,
    auth.uid(),
    coalesce(nullif(trim(coalesce(p_actor_name, '')), ''), 'system'),
    'task_update',
    '订单任务状态更新',
    jsonb_build_object('task_id', v_task.id, 'task_name', v_task.task_name, 'status', v_previous_status),
    jsonb_build_object('task_id', v_task.id, 'task_name', v_task.task_name, 'status', v_task.status)
  )
  returning * into v_log;

  return jsonb_build_object(
    'task', to_jsonb(v_task),
    'operation_log', to_jsonb(v_log),
    'previous_status', v_previous_status,
    'status', v_task.status
  );
end;
$$;

revoke execute on function app_update_order_task_status(uuid, text, text) from public, anon;
grant execute on function app_update_order_task_status(uuid, text, text) to authenticated, service_role;

-- ============================================================
-- supabase/migrations/20260602073915_dashboard_summary_rpc.sql
-- ============================================================
create or replace function app_dashboard_summary()
returns jsonb
language plpgsql
security invoker
set search_path = public
as $$
declare
  v_today_leads integer := 0;
  v_active_quotes integer := 0;
  v_executing_orders integer := 0;
  v_projected_profit numeric(18,2) := 0;
  v_pending_email_tasks integer := 0;
  v_low_margin_quotes integer := 0;
  v_orders_need_costs integer := 0;
  v_pending_receivables integer := 0;
begin
  if not app_is_any_role(array['admin', 'manager', 'sales', 'ops', 'finance', 'marketing']) then
    raise exception 'insufficient_dashboard_role' using errcode = '42501';
  end if;

  select count(*)::integer
  into v_today_leads
  from leads
  where created_at >= current_date
    and created_at < current_date + interval '1 day';

  select count(*)::integer
  into v_active_quotes
  from quotes
  where status in ('draft', 'sent', 'negotiating')
    and approval_status <> 'rejected';

  select count(*)::integer
  into v_executing_orders
  from orders
  where status in ('booked', 'in_transit', 'customs');

  select coalesce(sum(
    case
      when coalesce(actual_profit_total, 0) <> 0 then actual_profit_total
      else quoted_profit_total
    end
  ), 0)
  into v_projected_profit
  from orders
  where status in ('booked', 'in_transit', 'customs', 'delivered');

  select count(*)::integer
  into v_pending_email_tasks
  from email_tasks
  where status = 'pending'
    and scheduled_at <= now() + interval '1 day';

  select count(*)::integer
  into v_low_margin_quotes
  from quotes
  where status in ('draft', 'sent', 'negotiating')
    and estimated_profit_margin < 0.18;

  select count(*)::integer
  into v_orders_need_costs
  from orders
  where status in ('booked', 'in_transit', 'customs')
    and not exists (
      select 1
      from order_costs
      where order_costs.order_id = orders.id
        and order_costs.status in ('confirmed', 'approved', 'paid')
    )
    and not exists (
      select 1
      from payables
      where payables.order_id = orders.id
    );

  select count(*)::integer
  into v_pending_receivables
  from receivables
  where status in ('open', 'partial', 'overdue')
    and balance_amount > 0;

  return jsonb_build_object(
    'source', 'database',
    'generated_at', now(),
    'metrics', jsonb_build_array(
      jsonb_build_object(
        'key', 'today_leads',
        'label', '今日新增线索',
        'value', v_today_leads,
        'display_value', v_today_leads::text,
        'hint', '按当前账号可见的 leads 实时统计'
      ),
      jsonb_build_object(
        'key', 'active_quotes',
        'label', '进行中报价',
        'value', v_active_quotes,
        'display_value', v_active_quotes::text,
        'hint', '草稿、已发送、谈判中的报价'
      ),
      jsonb_build_object(
        'key', 'executing_orders',
        'label', '执行中订单',
        'value', v_executing_orders,
        'display_value', v_executing_orders::text,
        'hint', '已订舱、运输中、报关中的订单'
      ),
      jsonb_build_object(
        'key', 'projected_profit',
        'label', '预计毛利',
        'value', v_projected_profit,
        'display_value', '$' || to_char(v_projected_profit, 'FM999G999G999D00'),
        'hint', '按订单实际/报价利润汇总'
      )
    ),
    'workbench', jsonb_build_object(
      'pending_email_tasks', v_pending_email_tasks,
      'low_margin_quotes', v_low_margin_quotes,
      'orders_need_costs', v_orders_need_costs,
      'pending_receivables', v_pending_receivables
    )
  );
end;
$$;

revoke execute on function app_dashboard_summary() from public, anon;
grant execute on function app_dashboard_summary() to authenticated, service_role;

-- ============================================================
-- supabase/migrations/20260602075118_auto_lead_followup_trigger.sql
-- ============================================================
create or replace function app_auto_prepare_new_lead()
returns trigger
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_lead leads%rowtype;
  v_template email_templates%rowtype;
  v_template_code text;
  v_delay_hours integer;
  v_priority integer;
begin
  perform app_score_lead(new.id);

  select *
  into v_lead
  from leads
  where id = new.id;

  if v_lead.id is null or coalesce(v_lead.email, '') = '' then
    return new;
  end if;

  v_template_code := case
    when coalesce(v_lead.lead_score, 0) < 55 then 'reactivation_en'
    else 'lead_thank_you_en'
  end;

  select *
  into v_template
  from email_templates
  where template_code = v_template_code
    and is_active = true
  limit 1;

  if v_template.id is null then
    return new;
  end if;

  if exists (
    select 1
    from email_tasks
    where lead_id = v_lead.id
      and status = 'pending'
      and template_code = v_template.template_code
  ) then
    return new;
  end if;

  v_delay_hours := case
    when coalesce(v_lead.lead_score, 0) >= 80 then 1
    when coalesce(v_lead.lead_score, 0) >= 55 then 24
    else 72
  end;

  v_priority := case
    when coalesce(v_lead.lead_score, 0) >= 80 then 10
    when coalesce(v_lead.lead_score, 0) >= 55 then 30
    else 60
  end;

  insert into email_tasks (
    lead_id,
    contact_id,
    trigger_ref_type,
    trigger_ref_id,
    scheduled_at,
    status,
    owner_id,
    template_code,
    channel,
    subject_snapshot,
    body_snapshot,
    priority
  )
  values (
    v_lead.id,
    null,
    'auto_new_lead',
    v_lead.id,
    now() + make_interval(hours => v_delay_hours),
    'pending',
    v_lead.assigned_to,
    v_template.template_code,
    'email',
    v_template.subject,
    coalesce(v_template.body_text, regexp_replace(coalesce(v_template.body_html, ''), '<[^>]+>', '', 'g')),
    v_priority
  );

  update leads
  set
    next_best_action = coalesce(next_best_action, '系统已自动排入二次邮件跟进队列。'),
    updated_at = now()
  where id = v_lead.id;

  return new;
end;
$$;

revoke execute on function app_auto_prepare_new_lead() from public, anon, authenticated;

drop trigger if exists trg_auto_prepare_new_lead on leads;
create trigger trg_auto_prepare_new_lead
after insert on leads
for each row
execute function app_auto_prepare_new_lead();

